"use strict";(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[231],{3231:function(e,t,n){n.d(t,{ArticleJsonLd:function(){return u},BreadcrumbJsonLd:function(){return d},FAQPageJsonLd:function(){return c},LocalBusinessJsonLd:function(){return s},ServiceJsonLd:function(){return l}});var a=n(7437),i=n(644);let o=i.kQ.company,r="https://winaircleaning.com";function s(){let{areaName:e}=arguments.length>0&&void 0!==arguments[0]?arguments[0]:{},t={"@context":"https://schema.org","@type":"HVACBusiness",name:o.name,description:o.tagline,telephone:o.phone,email:o.email,url:r,image:"".concat(r,"/logo.jpg"),priceRange:"$$",address:{"@type":"PostalAddress",streetAddress:"5847 Wilshire Blvd",addressLocality:"Los Angeles",addressRegion:"CA",postalCode:"90036",addressCountry:"US"},geo:{"@type":"GeoCoordinates",latitude:34.0626,longitude:-118.3476},aggregateRating:{"@type":"AggregateRating",ratingValue:"4.9",reviewCount:127,bestRating:"5",worstRating:"1"},openingHoursSpecification:[{"@type":"OpeningHoursSpecification",dayOfWeek:["Monday","Tuesday","Wednesday","Thursday","Friday"],opens:"08:00",closes:"18:00"},{"@type":"OpeningHoursSpecification",dayOfWeek:"Saturday",opens:"09:00",closes:"15:00"}],areaServed:e?[{"@type":"City",name:e}]:i.kQ.areas.map(e=>({"@type":"City",name:e.name})),sameAs:[]};return(0,a.jsx)("script",{type:"application/ld+json",dangerouslySetInnerHTML:{__html:JSON.stringify(t)}})}function l(e){let{serviceName:t,serviceDescription:n,areaServed:r}=e,s={"@context":"https://schema.org","@type":"Service",name:t,description:n,provider:{"@type":"HVACBusiness",name:o.name,telephone:o.phone,address:{"@type":"PostalAddress",streetAddress:"5847 Wilshire Blvd",addressLocality:"Los Angeles",addressRegion:"CA",postalCode:"90036",addressCountry:"US"}},areaServed:r?r.map(e=>({"@type":"City",name:e})):i.kQ.areas.map(e=>({"@type":"City",name:e.name}))};return(0,a.jsx)("script",{type:"application/ld+json",dangerouslySetInnerHTML:{__html:JSON.stringify(s)}})}function c(e){let{faqs:t}=e,n={"@context":"https://schema.org","@type":"FAQPage",mainEntity:t.map(e=>({"@type":"Question",name:e.question,acceptedAnswer:{"@type":"Answer",text:e.answer}}))};return(0,a.jsx)("script",{type:"application/ld+json",dangerouslySetInnerHTML:{__html:JSON.stringify(n)}})}function d(e){let{items:t}=e,n={"@context":"https://schema.org","@type":"BreadcrumbList",itemListElement:t.map((e,t)=>({"@type":"ListItem",position:t+1,name:e.name,item:"".concat(r).concat(e.href)}))};return(0,a.jsx)("script",{type:"application/ld+json",dangerouslySetInnerHTML:{__html:JSON.stringify(n)}})}function u(e){let{headline:t,description:n,datePublished:i}=e,s={"@context":"https://schema.org","@type":"Article",headline:t,description:n,datePublished:i||"2024-01-15",author:{"@type":"Organization",name:o.name},publisher:{"@type":"Organization",name:o.name,logo:{"@type":"ImageObject",url:"".concat(r,"/logo.jpg")}}};return(0,a.jsx)("script",{type:"application/ld+json",dangerouslySetInnerHTML:{__html:JSON.stringify(s)}})}},644:function(e,t,n){n.d(t,{kQ:function(){return a},U2:function(){return i},BZ:function(){return o}});let a=JSON.parse('{"company":{"name":"Win Air Cleaning","type":"Air Duct & HVAC Cleaning","location":"Los Angeles, CA","city":"Los Angeles","state":"CA","state_full":"California","phone":"(555) 924-7100","email":"info@winaircleaning.com","tagline":"Professional air cleaning services dedicated to improving your indoor environment. Our expert team specializes in air duct and vent cleaning to ensure fresh, clean, and healthy air flow for your home or business.","year_established":"2014","certifications":["NADCA Certified","Licensed","Insured","Bonded","EPA Compliant"]},"home":{"hero":{"headline":"Breathe Cleaner Air Starting Today","subheadline":"Win Air Cleaning delivers expert air duct and HVAC cleaning across Los Angeles, so every breath in your home feels fresh and healthy.","cta_primary":"Get Free Estimate","cta_secondary":"Call Now","badge":"Trusted by 1,500+ Los Angeles Homeowners"},"stats":[{"value":"10+","label":"Years in Los Angeles"},{"value":"3,500+","label":"Homes Cleaned"},{"value":"4.9","label":"Star Rating"},{"value":"100%","label":"Satisfaction Guaranteed"}],"why_us":[{"title":"Before and After Photo Report","description":"We photograph every duct before and after cleaning, so you can see exactly what we removed. No guesswork, no vague promises. Just visible proof that your air system is spotless.","icon":"Eye"},{"title":"NADCA-Certified Technicians Only","description":"Every technician on our team holds active NADCA certification, the gold standard in air duct cleaning. We follow source-removal methods that actually eliminate contaminants rather than just stir them around.","icon":"Award"},{"title":"We Clean the Whole System, Not Just Vents","description":"Most companies vacuum a few registers and call it done. We clean your entire HVAC system from the air handler to every branch line, including the blower, coils, and plenums.","icon":"Scan"},{"title":"Flat-Rate Pricing with Zero Surprises","description":"We quote per system, not per vent, so there are no surprise charges when we find extra registers. The price you see at the estimate is the price you pay, period.","icon":"DollarSign"}]},"about":{"headline":"About Win Air Cleaning","paragraphs":["Win Air Cleaning was founded in 2014 with a simple mission: help Los Angeles families breathe easier at home. Over the last decade, we have grown from a two-person crew into a full NADCA-certified team serving homes and businesses across LA County. We know this city\'s unique air quality challenges, from wildfire smoke season to the fine dust that settles in coastal neighborhoods year-round.","Our technicians are trained in source-removal cleaning methods and carry NADCA, EPA, and OSHA certifications. We use commercial-grade negative air machines and rotary brush systems that outperform the equipment most competitors rely on. Every job follows a documented checklist so nothing in your HVAC system gets overlooked.","We believe the air inside your home matters more than the air outside. That is why every Win Air Cleaning job comes with a satisfaction guarantee, a post-cleaning inspection, and a photo report you can keep for your records. We are active members of the Los Angeles business community and proud to support local youth sports leagues across the county."],"values":[{"title":"Show the Work, Every Time","description":"We document every job with before and after photos because we want you to see the difference, not just take our word for it. Transparency is not a policy here. It is how we built our reputation.","icon":"Eye"},{"title":"Built on Referrals, Not Ads","description":"More than half of our new customers come from a friend or neighbor who already used us. We would rather earn your recommendation through great work than chase you with marketing.","icon":"Users"},{"title":"Your Air, Year-Round","description":"LA air quality shifts with the seasons, and your HVAC system collects whatever is in the air. We help our customers set up maintenance plans so their ducts stay clean through wildfire season, Santa Ana winds, and everything in between.","icon":"Wind"},{"title":"Obsessed With the Details Others Skip","description":"We clean behind return air grilles, inside blower compartments, and along flex duct runs that other companies ignore. The parts of your system you cannot see are often the dirtiest, and we never leave them untouched.","icon":"Scan"}]},"services":[{"slug":"residential-air-duct-cleaning","name":"Residential Air Duct Cleaning","icon":"Home","image_prompt":"Close-up of a clean residential HVAC air duct interior, polished silver metal duct walls reflecting light, no dust or debris visible. No people, no faces. Sharp focus, natural light. Photorealistic, high-resolution, no text, no logos.","short_description":"Complete cleaning of your home\'s ductwork using NADCA-approved source-removal methods. We clear dust, allergens, pet dander, and debris from every supply and return line so your family breathes cleaner air.","full_description":["Your home\'s air ducts collect years of dust, pet dander, pollen, and debris that your filter alone cannot catch. Every time your HVAC runs, those contaminants circulate through the rooms where you sleep, cook, and spend time with your family. Residential air duct cleaning removes that buildup at the source, giving you noticeably fresher indoor air from the moment the job is done.","Our process starts with a full inspection of your duct system using a remote camera. We then seal your registers, connect a commercial negative-air machine to put the entire system under vacuum, and use rotary brushes to dislodge debris from every branch line. Loosened contaminants are pulled into our collection unit and removed from your home entirely. We finish by sanitizing the system and replacing your filter.","Win Air Cleaning has cleaned over 3,500 Los Angeles homes since 2014. Whether you live in a 1940s bungalow in Silver Lake or a modern build in Playa Vista, our technicians know how to handle every duct configuration. We leave you with a photo report and a clean system you can trust."],"features":["Full system vacuum with commercial negative-air machine","Rotary brush agitation on all supply and return lines","Remote camera inspection before and after cleaning","Register and grille cleaning included","Optional antimicrobial sanitizing treatment","Post-cleaning photo report delivered to your inbox"],"faq":[{"question":"How often should I have my home\'s air ducts cleaned?","answer":"For most Los Angeles homes, every 3 to 5 years is ideal. If you have pets, allergies, or recently completed a renovation, we recommend cleaning every 2 to 3 years. Our technicians can assess your system and give you a personalized schedule."},{"question":"Will duct cleaning make a mess in my house?","answer":"Not at all. We seal every register before we begin and use negative-air pressure to contain all debris inside our collection system. We also lay down protective coverings on your floors. Most customers tell us their home feels cleaner after we leave than before we arrived."},{"question":"How long does a typical residential duct cleaning take?","answer":"A standard home takes 3 to 5 hours depending on the size of the system and number of vents. We schedule enough time so our technicians never rush, because thoroughness matters more than speed."}]},{"slug":"commercial-air-duct-cleaning","name":"Commercial Air Duct Cleaning","icon":"Building","image_prompt":"Wide-angle view of clean commercial HVAC ductwork in a ceiling plenum, large rectangular galvanized ducts with fresh insulation, neat connections. No people, no faces. Sharp focus, natural light. Photorealistic, high-resolution, no text, no logos.","short_description":"Professional air duct cleaning for offices, retail spaces, restaurants, and commercial buildings across Los Angeles. We work around your schedule to minimize disruption to your business.","full_description":["Commercial HVAC systems run harder and longer than residential units, which means they accumulate contaminants faster. Dirty ducts in a business setting affect employee health, customer comfort, and even your energy bills. Win Air Cleaning provides thorough commercial duct cleaning that meets NADCA standards and helps you maintain a healthy, productive work environment.","We begin every commercial project with a detailed walkthrough and system assessment. Our team maps your ductwork, identifies problem areas, and develops a cleaning plan that fits your operating hours. We can work nights and weekends so your business stays open during the process. Our industrial-grade equipment handles large-diameter ductwork, rooftop units, and multi-zone systems with ease.","From small offices in West Hollywood to restaurant kitchens in Downtown LA, we have cleaned commercial spaces of every size and type. We provide detailed documentation for your records, which is especially useful for health inspections and lease compliance. Let us help your business put its best air forward."],"features":["NADCA-compliant cleaning for all commercial duct types","After-hours and weekend scheduling available","Rooftop unit and multi-zone system capability","Detailed compliance documentation provided","Industrial negative-air machines for large systems","Customized maintenance contracts for ongoing care"],"faq":[{"question":"Can you clean ducts in my business without shutting down operations?","answer":"Yes. We routinely work after hours, on weekends, and in sections so your business stays open. We coordinate with your team to minimize disruption and complete the job on your schedule."},{"question":"Do you handle restaurant kitchen ductwork?","answer":"We clean the HVAC supply and return ducts in restaurant environments. For kitchen exhaust hood and grease duct cleaning, we recommend a certified kitchen exhaust specialist, but we are happy to coordinate referrals."},{"question":"How often do commercial ducts need cleaning?","answer":"NADCA recommends commercial duct cleaning every 3 to 5 years, but high-traffic spaces like medical offices and restaurants may benefit from more frequent service. We assess your system and recommend a schedule based on usage."}]},{"slug":"hvac-system-cleaning","name":"HVAC System Cleaning","icon":"Thermometer","image_prompt":"Close-up of a clean HVAC blower fan and evaporator coil assembly, shiny metal fins perfectly aligned, interior of air handler spotless and dust-free. No people, no faces. Sharp focus, natural light. Photorealistic, high-resolution, no text, no logos.","short_description":"Deep cleaning of your entire HVAC system including the air handler, blower motor, evaporator coil, and condensate drain. A clean system runs more efficiently and lasts longer.","full_description":["Your air ducts are only part of the story. The air handler, blower motor, evaporator coil, and condensate drain pan all collect grime that reduces airflow, drives up energy costs, and shortens the life of your equipment. HVAC system cleaning addresses every component so your unit runs the way it was designed to.","Our technicians open the air handler cabinet and carefully clean the blower wheel, motor housing, and evaporator coil using specialized brushes and approved cleaning solutions. We clear the condensate drain line to prevent water damage and mold growth. The entire process improves airflow, reduces strain on the compressor, and can lower your monthly energy bill by 15 to 25 percent.","In Los Angeles, your HVAC system works hard nearly year-round. Regular system cleaning extends equipment life and keeps your warranty intact. Win Air Cleaning recommends pairing this service with a full duct cleaning for the most complete result."],"features":["Blower wheel and motor housing cleaning","Evaporator coil deep cleaning","Condensate drain line flush and treatment","Air handler cabinet interior wipe-down","Airflow measurement before and after service","Pairs with duct cleaning for a full-system refresh"],"faq":[{"question":"Is HVAC system cleaning different from duct cleaning?","answer":"Yes. Duct cleaning focuses on the supply and return air pathways. HVAC system cleaning targets the mechanical components: the blower, coil, and drain system. For the best results, we recommend doing both together."},{"question":"Will this void my HVAC warranty?","answer":"No. In fact, many manufacturers recommend regular cleaning to keep your warranty valid. We follow manufacturer guidelines and use approved cleaning methods on all equipment."},{"question":"How much can I save on energy bills after an HVAC cleaning?","answer":"Most Los Angeles homeowners see a 15 to 25 percent reduction in cooling costs after a thorough system cleaning. The exact savings depend on how dirty your system was and how often you run your unit."}]},{"slug":"dryer-vent-cleaning","name":"Dryer Vent Cleaning","icon":"Flame","image_prompt":"Close-up of a clean dryer vent exhaust hood on an exterior wall, shiny aluminum vent flap open with clear airflow path, no lint buildup visible. No people, no faces. Sharp focus, natural light. Photorealistic, high-resolution, no text, no logos.","short_description":"Lint and debris removal from your dryer vent line to prevent fire hazards, reduce drying times, and extend the life of your dryer. One of the most important safety services for any home.","full_description":["Clogged dryer vents cause nearly 3,000 house fires in the United States every year, and lint buildup is the leading cause. A blocked vent also forces your dryer to work harder, increasing energy costs and shortening the appliance\'s lifespan. Dryer vent cleaning is a simple service that protects your family and your wallet.","We disconnect your dryer, access the vent line, and use a high-powered rotary brush system combined with compressed air to remove every bit of lint from the duct. We clean from the dryer connection all the way to the exterior exhaust hood. After cleaning, we reconnect your dryer, test airflow at the outlet, and verify proper exhaust function.","Many Los Angeles homes have long or winding dryer vent runs that trap more lint than standard setups. Our team handles vents routed through walls, ceilings, and rooftops. We recommend cleaning your dryer vent at least once a year, or more often if you do heavy laundry loads."],"features":["Full-length vent line cleaning from dryer to exterior","Rotary brush and compressed air lint removal","Exterior exhaust hood inspection and cleaning","Airflow verification after cleaning","Fire hazard risk assessment included","Annual maintenance reminders available"],"faq":[{"question":"How do I know if my dryer vent is clogged?","answer":"Common signs include clothes taking longer than one cycle to dry, the dryer feeling unusually hot to the touch, a burning smell during operation, and visible lint around the exterior vent hood. If you notice any of these, call us right away."},{"question":"How often should dryer vents be cleaned?","answer":"At least once per year for most households. If you have a large family, do frequent laundry, or your vent run is longer than 15 feet, twice a year is safer. We can assess your setup and recommend the right schedule."},{"question":"Can you clean dryer vents that go through the roof?","answer":"Yes. Our team has the equipment and experience to clean roof-vented dryer lines safely. We access the vent from both the interior and exterior to ensure complete lint removal."}]},{"slug":"indoor-air-quality-testing","name":"Indoor Air Quality Testing","icon":"Gauge","image_prompt":"Close-up of a digital indoor air quality monitor displaying green readings on a countertop, clear LCD screen showing PM2.5 and humidity levels, modern device design. No people, no faces. Sharp focus, natural light. Photorealistic, high-resolution, no text, no logos.","short_description":"Professional air quality assessment to identify pollutants, allergens, mold spores, and VOCs in your home. Know exactly what you are breathing before deciding on a treatment plan.","full_description":["You cannot fix what you cannot measure. Indoor air quality testing gives you hard data on what is circulating through your home, from particulate matter and mold spores to volatile organic compounds and carbon dioxide levels. In Los Angeles, where outdoor air quality regularly ranks among the worst in the nation, knowing your indoor levels is especially important.","Our technicians use calibrated professional-grade monitors to sample the air in multiple rooms of your home. We measure PM2.5 and PM10 particulate levels, relative humidity, CO2 concentration, and VOC levels. Results are compiled into a clear, easy-to-read report with specific recommendations for improving your air quality.","Air quality testing is an ideal first step before scheduling duct cleaning, HVAC service, or adding filtration upgrades. It is also valuable after renovations, water damage events, or if household members are experiencing unexplained allergy symptoms. Win Air Cleaning provides honest assessments and only recommends services that will actually make a difference."],"features":["Multi-room air sampling with calibrated instruments","PM2.5, PM10, CO2, humidity, and VOC measurements","Clear written report with actionable recommendations","Ideal baseline test before duct or HVAC cleaning","Post-renovation and post-remediation testing available","No upselling. We only recommend what the data supports."],"faq":[{"question":"What pollutants do you test for?","answer":"We measure fine and coarse particulate matter (PM2.5 and PM10), carbon dioxide, volatile organic compounds, relative humidity, and temperature. If you suspect mold, we can add mold spore sampling to the assessment."},{"question":"How long does air quality testing take?","answer":"A typical residential test takes about 1 to 2 hours. We sample the air in your main living areas, bedrooms, and near your HVAC system to get a complete picture of your indoor environment."},{"question":"Will testing tell me if I need duct cleaning?","answer":"It is one of the best ways to find out. High particulate levels often point to dirty ductwork or a failing filter. We use your results to make honest recommendations, and we never push services your home does not need."}]},{"slug":"mold-remediation-in-ducts","name":"Mold Remediation in Ducts","icon":"ShieldCheck","image_prompt":"Close-up of a clean air duct interior wall after remediation, smooth clean metal surface with antimicrobial coating visible, bright even lighting inside the duct. No people, no faces. Sharp focus, natural light. Photorealistic, high-resolution, no text, no logos.","short_description":"Identification and removal of mold growth inside your air duct system. We eliminate the contamination and apply antimicrobial treatments to prevent it from returning.","full_description":["Mold inside your ductwork is more than an unpleasant smell. Every time your HVAC system cycles, it pushes mold spores into your living spaces, triggering allergies, asthma, and respiratory problems. In Southern California\'s coastal climate, condensation inside ducts creates ideal conditions for mold to thrive, especially in older homes and buildings with poor insulation.","Our mold remediation process begins with a visual inspection and air sampling to identify the type and extent of growth. We isolate the affected sections, use HEPA-filtered negative air machines to contain spores, and physically remove all visible mold from duct surfaces. After cleaning, we apply an EPA-registered antimicrobial coating to treated areas and address the moisture source that caused the growth.","Win Air Cleaning follows strict EPA and NADCA guidelines for mold remediation in HVAC systems. We document every step of the process with photos and provide a clearance report when the job is complete. If your home has a musty smell or your family has been dealing with unexplained respiratory issues, mold in your ducts could be the cause."],"features":["Visual and air-sample mold identification","HEPA-filtered containment during remediation","Physical removal of all visible mold growth","EPA-registered antimicrobial coating application","Moisture source assessment and recommendations","Post-remediation clearance report with photos"],"faq":[{"question":"How do I know if there is mold in my ducts?","answer":"A musty or earthy odor when the HVAC runs is the most common sign. You may also notice dark discoloration around registers or experience increased allergy symptoms indoors. We can perform an inspection and air test to confirm."},{"question":"Is mold in air ducts dangerous?","answer":"Yes. Mold spores circulated through your HVAC system can cause respiratory irritation, allergic reactions, and worsen asthma. Certain mold types produce mycotoxins that pose more serious health risks. Prompt remediation is important."},{"question":"Can mold come back after remediation?","answer":"It can if the moisture source is not addressed. That is why we assess and fix the underlying cause, whether it is condensation, a leak, or poor insulation. Our antimicrobial coating also provides lasting protection on treated surfaces."}]},{"slug":"uv-light-air-purification","name":"UV Light Air Purification","icon":"Sun","image_prompt":"Close-up of a UV-C germicidal light installed inside an HVAC air handler, blue-violet UV glow illuminating clean evaporator coils, sterile clinical appearance. No people, no faces. Sharp focus, natural light. Photorealistic, high-resolution, no text, no logos.","short_description":"Installation of UV-C germicidal lights inside your HVAC system to continuously neutralize bacteria, viruses, and mold spores as air circulates through your home.","full_description":["UV-C germicidal lights installed inside your HVAC system work around the clock to destroy bacteria, viruses, and mold spores as air passes through the unit. This technology is used in hospitals and laboratories worldwide and is now available for residential and commercial HVAC systems at an affordable price point.","We install commercial-grade UV-C lamps near the evaporator coil and in the return air plenum, the two areas where microbial growth is most likely. The UV light disrupts the DNA of airborne pathogens, rendering them unable to reproduce. The system runs silently whenever your HVAC operates and requires only an annual bulb replacement.","For Los Angeles homes dealing with allergies, asthma, or concerns about airborne illness, UV purification adds a powerful layer of protection. Win Air Cleaning pairs this service with duct cleaning and HVAC system cleaning for a comprehensive indoor air quality solution. We use only UL-listed, ozone-free UV-C units to keep your home safe."],"features":["Commercial-grade UV-C germicidal lamp installation","Positioned at evaporator coil and return plenum","Destroys bacteria, viruses, and mold on contact","Ozone-free, UL-listed units only","Silent operation with no maintenance between bulb changes","Annual bulb replacement service available"],"faq":[{"question":"Do UV lights in HVAC systems actually work?","answer":"Yes. UV-C light at 254 nanometers is proven to destroy the DNA of bacteria, viruses, and mold spores. When installed correctly near the evaporator coil, UV systems significantly reduce microbial contamination in your air supply."},{"question":"Are UV-C lights safe for my family?","answer":"Completely. The UV light is contained inside your HVAC system and never reaches your living spaces. We use ozone-free units that meet all UL safety standards, so there is no risk to your household."},{"question":"How often do UV-C bulbs need to be replaced?","answer":"UV-C bulbs are effective for about 12 months before their germicidal output drops below useful levels. We offer an annual replacement service so you never have to think about it."}]},{"slug":"electrostatic-filter-installation","name":"Electrostatic Filter Installation","icon":"Zap","image_prompt":"Close-up of a new electrostatic air filter being held at an angle showing its layered mesh structure, metallic woven media catching light, clean and unused. No people, no faces. Sharp focus, natural light. Photorealistic, high-resolution, no text, no logos.","short_description":"Upgrade from disposable filters to permanent, washable electrostatic filters that capture more particles and save you money over time. Better filtration with less waste.","full_description":["Standard disposable filters catch only the largest dust particles and need replacing every month or two. Electrostatic filters use static charge generated by airflow to attract and trap particles as small as 1 micron, including pollen, pet dander, dust mites, and smoke particles. They are washable, reusable, and last for years.","We measure your existing filter slot, recommend the right electrostatic filter for your system, and install it on site. We also show you how to wash and maintain the filter so it keeps performing at peak efficiency. For homes in Los Angeles, where wildfire smoke and urban particulate are ongoing concerns, electrostatic filters offer a meaningful step up in air quality.","Win Air Cleaning recommends pairing electrostatic filter installation with a duct cleaning for the best results. A clean system combined with superior filtration keeps your indoor air noticeably cleaner between professional service visits. Most customers recoup the cost of the filter within a year by eliminating monthly disposable purchases."],"features":["Permanent, washable electrostatic media","Captures particles as small as 1 micron","Custom-sized to fit your existing filter slot","Eliminates monthly disposable filter purchases","Lifetime filter with simple rinse-and-dry maintenance","Ideal for allergy sufferers and pet owners"],"faq":[{"question":"How does an electrostatic filter work?","answer":"As air passes through the layered media, friction creates a static charge that attracts airborne particles like a magnet. The filter captures dust, pollen, pet dander, and smoke particles without restricting airflow to your HVAC system."},{"question":"How often do I need to wash an electrostatic filter?","answer":"We recommend rinsing it every 30 to 60 days depending on your household. Homes with pets or heavy dust should wash monthly. The process takes about five minutes with a garden hose."},{"question":"Will an electrostatic filter work with my current HVAC system?","answer":"In most cases, yes. Electrostatic filters are designed to fit standard filter slots and do not require any modifications to your system. We measure your slot on site and install the right size for a proper seal."}]},{"slug":"sanitizing-and-deodorizing","name":"Sanitizing & Deodorizing","icon":"Droplets","image_prompt":"Close-up of a fogger nozzle releasing fine antimicrobial mist inside an HVAC duct, soft white vapor dispersing evenly through a clean metal ductwork interior. No people, no faces. Sharp focus, natural light. Photorealistic, high-resolution, no text, no logos.","short_description":"EPA-registered antimicrobial treatment applied throughout your duct system to eliminate bacteria, neutralize odors, and leave your home smelling fresh and clean.","full_description":["Even after a thorough duct cleaning, bacteria and odor-causing compounds can linger on duct surfaces. Our sanitizing and deodorizing service applies an EPA-registered antimicrobial fog throughout your entire duct system, killing bacteria on contact and neutralizing odors from pets, cooking, smoke, and mustiness.","We use a ULV (ultra-low volume) fogger that disperses a fine mist evenly through every branch of your ductwork. The treatment coats interior surfaces and continues to inhibit microbial growth for months after application. It is safe for use in homes with children and pets, and it leaves no chemical residue or strong fragrance.","This service is especially popular with Los Angeles homeowners who have recently moved into a new home, completed renovations, or dealt with water damage. It is also a great add-on after a standard duct cleaning for families with allergies or sensitivities. Win Air Cleaning only uses products that are EPA-registered and proven effective."],"features":["EPA-registered antimicrobial treatment","ULV fogger for even whole-system coverage","Neutralizes pet, smoke, cooking, and musty odors","Safe for homes with children and pets","No chemical residue or strong fragrance","Inhibits microbial regrowth for months"],"faq":[{"question":"Is the sanitizing treatment safe for my family?","answer":"Yes. We use only EPA-registered products that are approved for use in occupied spaces. The treatment leaves no harmful residue and is safe for children, pets, and people with sensitivities."},{"question":"How long does the sanitizing effect last?","answer":"The antimicrobial coating continues to inhibit bacterial growth for 3 to 6 months depending on conditions. We recommend pairing it with regular duct cleaning for ongoing protection."},{"question":"Will this remove cigarette smoke smell from my ducts?","answer":"It significantly reduces smoke odor in most cases. For heavy or long-term smoke contamination, we may recommend a full duct cleaning followed by multiple sanitizing treatments for the best results."}]},{"slug":"hvac-maintenance-plans","name":"HVAC Maintenance Plans","icon":"Layers","image_prompt":"Flat lay of an HVAC maintenance checklist on a clipboard next to clean air filters and a set of precision tools on a white surface, organized and professional. No people, no faces. Sharp focus, natural light. Photorealistic, high-resolution, no text, no logos.","short_description":"Scheduled annual or semi-annual HVAC and duct maintenance to keep your system clean, efficient, and long-lasting. Priority scheduling and discounted rates for plan members.","full_description":["The best time to clean your ducts is before they become a problem. Our maintenance plans take the guesswork out of HVAC care by putting your cleanings, inspections, and filter services on a regular schedule. You never have to remember when your last service was or wonder if your system needs attention.","Plan members receive annual or semi-annual duct and HVAC system cleanings, priority scheduling during busy seasons, and a 15 percent discount on all additional services. We also perform a system health check at every visit, catching small issues before they become expensive repairs. You get a consistent point of contact on our team who knows your home and your system.","For Los Angeles homeowners, a maintenance plan is especially valuable. Between wildfire smoke, seasonal pollen, and the dust that comes with dry Santa Ana winds, your system accumulates contaminants faster than in most parts of the country. Win Air Cleaning members stay ahead of it all with a plan built around their home and their schedule."],"features":["Annual or semi-annual service visits","Priority scheduling during peak seasons","15% discount on all additional services","System health check at every visit","Dedicated technician familiar with your home","Flexible plans for residential and commercial clients"],"faq":[{"question":"What is included in a maintenance plan?","answer":"Each plan includes scheduled duct and HVAC system cleanings, filter replacement or cleaning, a system health check, priority booking, and a 15 percent discount on any additional services. We customize plans to fit your home and budget."},{"question":"Can I cancel my maintenance plan at any time?","answer":"Yes. Our plans run on an annual basis, but you can cancel at any time with no penalties or hidden fees. We want you to stay because of the value, not because of a contract."},{"question":"Do you offer maintenance plans for businesses?","answer":"Absolutely. We offer commercial maintenance plans with flexible scheduling, multi-unit discounts, and compliance documentation for businesses of all sizes across Los Angeles."}]}],"process_steps":[{"step":1,"title":"Schedule Your Free Assessment","description":"Call us or fill out our online form. We respond within 2 hours during business hours and schedule a visit at your convenience.","icon":"Phone"},{"step":2,"title":"On-Site Camera Inspection","description":"Our technician inspects your ductwork and HVAC system with a remote camera, explains what they find, and provides a flat-rate written estimate.","icon":"Eye"},{"step":3,"title":"Professional Source-Removal Cleaning","description":"We seal your registers, connect our negative-air machine, and use rotary brushes to clean every inch of your system from the air handler to each vent.","icon":"Wind"},{"step":4,"title":"Photo Report and Walk-Through","description":"We walk you through the before and after photos, verify airflow at every register, and do not leave until you are 100% satisfied with the results.","icon":"CheckCircle"}],"areas":[{"slug":"santa-monica","name":"Santa Monica","description":"Santa Monica\'s ocean breeze brings fresh air, but it also carries salt, moisture, and fine particulate into your home\'s duct system. Win Air Cleaning helps Santa Monica homeowners keep their indoor air as clean as the beachside views.","highlights":["Fast response times to all Santa Monica neighborhoods within 30 minutes","Experience with coastal moisture and salt-air corrosion in ductwork","Serving Santa Monica condos, apartments, and single-family homes since 2014"]},{"slug":"burbank","name":"Burbank","description":"Burbank homes deal with valley heat, wildfire smoke drift, and seasonal dust that settles into duct systems quickly. Regular duct cleaning keeps Burbank families breathing clean air all year, even during the worst air quality days.","highlights":["Familiar with Burbank\'s older ranch homes and their unique duct layouts","Quick scheduling for Burbank residents, often next-day availability","Trusted by hundreds of Burbank homeowners for repeat annual service"]},{"slug":"pasadena","name":"Pasadena","description":"From the historic homes near Old Town to the foothill neighborhoods along the Arroyo, Pasadena\'s housing stock spans over a century. Win Air Cleaning has the expertise to clean ductwork in vintage and modern Pasadena homes alike.","highlights":["Specialized in older Pasadena homes with original ductwork and tight layouts","Serving Pasadena\'s San Rafael, Bungalow Heaven, and Hastings Ranch neighborhoods","Post-wildfire smoke cleaning services for foothill communities"]},{"slug":"hollywood","name":"Hollywood","description":"Hollywood\'s dense mix of apartment buildings, condos, and hillside homes presents unique HVAC challenges. Win Air Cleaning serves Hollywood residents and property managers with flexible scheduling and commercial-grade equipment.","highlights":["Multi-unit building services for Hollywood apartment owners and managers","Hillside home access with portable equipment for tight spaces","Evening and weekend scheduling for busy Hollywood professionals"]},{"slug":"downtown-la","name":"Downtown LA","description":"Downtown LA lofts and high-rises rely on central HVAC systems that accumulate urban particulate, construction dust, and allergens. Win Air Cleaning keeps Downtown residents and offices breathing easy in the heart of the city.","highlights":["High-rise and loft HVAC experience with central system expertise","Serving DTLA residents, offices, and retail spaces since 2014","Commercial building compliance documentation included with every service"]},{"slug":"silver-lake","name":"Silver Lake","description":"Silver Lake\'s charming mid-century homes and hillside properties often have older HVAC systems that collect decades of dust and debris. Win Air Cleaning brings modern cleaning technology to Silver Lake\'s classic homes.","highlights":["Experienced with mid-century and 1920s-era ductwork common in Silver Lake","Portable equipment for hillside homes with limited driveway access","Popular among Silver Lake families with children and pets"]},{"slug":"west-hollywood","name":"West Hollywood","description":"West Hollywood\'s mix of stylish condos, apartments, and small commercial spaces demands cleaning crews who work efficiently in compact environments. Win Air Cleaning delivers thorough results in even the tightest West Hollywood spaces.","highlights":["Compact equipment designed for condo and apartment duct systems","Property management partnerships for multi-unit WeHo buildings","Flexible weekday and weekend scheduling to fit busy lifestyles"]},{"slug":"glendale","name":"Glendale","description":"Glendale homes experience valley heat and the same wildfire smoke patterns as Burbank, making regular duct cleaning essential. Win Air Cleaning is a trusted name among Glendale families for reliable, thorough HVAC care.","highlights":["Next-day availability for Glendale residents most of the year","Serving Glendale\'s Montrose, Sparr Heights, and Adams Hill neighborhoods","Repeat customers make up over 60% of our Glendale business"]}],"testimonials":[{"text":"Win Air Cleaning was incredibly thorough. They showed me camera footage of the inside of my ducts before and after, and the difference was shocking. My allergies have improved noticeably since the cleaning, and the whole house smells fresher. I wish I had done this years ago.","author":"Sarah M.","location":"Pasadena resident","rating":5,"service":"Residential Air Duct Cleaning"},{"text":"We manage several apartment buildings in Hollywood and needed a company that could handle multi-unit jobs without disrupting tenants. Win Air Cleaning worked around our schedule, cleaned every unit efficiently, and left the properties spotless. They have been our go-to team for two years now.","author":"David R.","location":"Hollywood property manager","rating":5,"service":"Commercial Air Duct Cleaning"},{"text":"I kept noticing a musty smell every time the AC kicked on. Win Air Cleaning found mold growing on my evaporator coil and inside two return ducts. They remediated everything, applied an antimicrobial treatment, and the smell is completely gone. Great communication throughout the whole process.","author":"Jessica T.","location":"Silver Lake resident","rating":5,"service":"Mold Remediation in Ducts"},{"text":"After the Eaton fire, our home was filled with that smoky residue smell for weeks. Win Air Cleaning came out, cleaned our entire duct system, replaced our filters, and ran a sanitizing treatment. The difference was immediate. They were professional, on time, and priced fairly.","author":"Michael K.","location":"Glendale resident","rating":5,"service":"Sanitizing & Deodorizing"},{"text":"I had no idea my dryer vent was almost completely blocked until Win Air Cleaning showed me the lint they pulled out. It was terrifying. The dryer runs so much faster now, and I feel safer knowing the fire risk is gone. They even sent a reminder when it was time for my next annual cleaning.","author":"Linda P.","location":"Santa Monica resident","rating":5,"service":"Dryer Vent Cleaning"},{"text":"We signed up for the annual maintenance plan after our first duct cleaning, and it has been worth every penny. Our technician knows our system, shows up on schedule, and catches small issues before they become big problems. The priority scheduling during wildfire season is a huge bonus.","author":"Brian W.","location":"Burbank resident","rating":5,"service":"HVAC Maintenance Plans"}],"blog":[{"slug":"how-often-should-you-clean-air-ducts-los-angeles","title":"How Often Should You Clean Your Air Ducts in Los Angeles?","excerpt":"Los Angeles air quality creates unique challenges for your home\'s HVAC system. Learn how often LA homeowners should schedule professional duct cleaning and what signs to watch for.","content":["Most HVAC experts recommend cleaning your air ducts every 3 to 5 years, but Los Angeles homeowners often need to clean more frequently. Between seasonal wildfire smoke, Santa Ana wind dust, and urban particulate pollution, LA duct systems accumulate contaminants faster than homes in other parts of the country. If you have pets, allergies, or live near a major road, the buildup happens even faster.","Watch for these signs that your ducts need attention: visible dust blowing from registers when the system starts, a musty or stale smell when the HVAC runs, increased allergy symptoms indoors, and higher than normal energy bills. If you have recently renovated your home, construction dust in your ducts is almost guaranteed. A camera inspection can tell you exactly what is inside your system.","Win Air Cleaning recommends an initial inspection for any Los Angeles home that has not had professional duct service in the last three years. Our team uses remote cameras to assess your system and provides honest recommendations based on what we find. Many of our customers set up annual maintenance plans to stay ahead of LA\'s air quality challenges year-round."],"category":"Guides"},{"slug":"wildfire-smoke-hvac-protection-tips","title":"Protecting Your HVAC System During Los Angeles Wildfire Season","excerpt":"Wildfire smoke does not stay outside. Here is how it gets into your duct system and what you can do to protect your home\'s air quality during fire season in Los Angeles.","content":["When wildfires burn in or near Los Angeles, smoke particles as small as 2.5 microns infiltrate your home through gaps, open doors, and your HVAC system\'s fresh air intake. Standard HVAC filters are not designed to capture particles this fine, which means smoke residue settles inside your ductwork and recirculates every time your system runs. Even after the skies clear, your ducts can continue spreading those contaminants for weeks.","During wildfire season, upgrade your HVAC filter to a MERV 13 rating or higher, seal any visible gaps around duct connections, and keep windows closed when air quality warnings are active. After a major smoke event, schedule a professional duct cleaning to remove the residue that your filter could not catch. Adding a UV light purification system provides an extra layer of defense against the organic compounds found in wildfire smoke.","Win Air Cleaning has helped hundreds of Los Angeles families recover their indoor air quality after wildfire events. Our post-smoke cleaning service includes a full duct and HVAC system cleaning, sanitizing treatment, and filter upgrade. If your home still smells like smoke after the fires have passed, your ducts are likely holding onto the problem."],"category":"Seasonal"},{"slug":"signs-dryer-vent-needs-cleaning","title":"5 Warning Signs Your Dryer Vent Needs Cleaning Right Now","excerpt":"A clogged dryer vent is one of the leading causes of house fires. Here are five warning signs every Los Angeles homeowner should know, and what to do about them.","content":["Dryer vent fires cause thousands of home fires across the United States every year, and the leading cause is lint buildup that restricts airflow. The danger builds gradually. You might not notice anything wrong until your clothes take two cycles to dry or your laundry room feels unusually warm. By that point, the fire risk is already elevated.","Here are five signs your dryer vent needs professional cleaning: your clothes take longer than 45 minutes to dry on a normal cycle, the top of the dryer is hot to the touch during operation, you smell a burning or musty odor when the dryer runs, lint is visible around the exterior vent hood, or it has been more than 12 months since your last cleaning. If you notice any of these, do not wait. Schedule a cleaning before using your dryer again.","Win Air Cleaning provides fast, thorough dryer vent cleaning across Los Angeles. We use rotary brushes and compressed air to clear your entire vent line from the dryer to the exterior outlet. Every service includes an airflow test to verify the vent is clear and functioning safely. For peace of mind, we offer annual reminders so you never fall behind on this critical maintenance."],"category":"Safety"},{"slug":"improve-indoor-air-quality-los-angeles-home","title":"7 Ways to Improve Indoor Air Quality in Your Los Angeles Home","excerpt":"Indoor air can be 2 to 5 times more polluted than outdoor air. Here are seven practical steps Los Angeles homeowners can take to breathe cleaner air at home.","content":["The EPA estimates that indoor air is typically 2 to 5 times more polluted than outdoor air, and in Los Angeles, outdoor air quality is already a concern. Your home traps cooking fumes, pet dander, cleaning product vapors, dust mites, and outdoor pollutants that drift in through open windows and your HVAC system. Taking steps to improve your indoor air quality makes a real difference for your health and comfort.","Start with these seven steps: upgrade your HVAC filter to MERV 11 or higher, schedule professional duct cleaning every 3 to 5 years, install a UV-C purification system in your air handler, use exhaust fans when cooking and showering, keep indoor humidity between 30 and 50 percent, vacuum with a HEPA-filter vacuum weekly, and have your dryer vent cleaned annually. Each step reduces the pollutant load in your home.","Win Air Cleaning can help with several of these steps in a single visit. Our technicians clean your ducts, service your HVAC system, install UV purification, and upgrade your filtration. We also perform indoor air quality testing to measure your starting point and track improvement. Better indoor air starts with knowing what you are breathing, and we give you the data to make smart decisions."],"category":"Tips"}],"contact":{"headline":"Contact Win Air Cleaning","subtitle":"Ready to breathe cleaner air? Get in touch for a free, no-obligation estimate.","address":"5847 Wilshire Blvd, Los Angeles, CA 90036","hours":"Mon-Fri: 8am-6pm | Sat: 9am-3pm | Emergency: Available","form_fields":["name","email","phone","service","message"]},"cta":{"headline":"Ready to Breathe Cleaner Air?","subtext":"Contact Win Air Cleaning today for a free, no-obligation estimate. We respond within 2 hours.","button_text":"Get My Free Quote"},"privacy":{"business_name":"Win Air Cleaning","email":"info@winaircleaning.com","data_collected":"Name, email, phone number, and message from contact forms.","third_party":"Netlify (hosting), Google Fonts, Google Analytics"},"footer":{"tagline":"Proudly serving Los Angeles and surrounding communities since 2014."}}');function i(){return a.services}function o(){return a.testimonials}}}]);